import { Component, computed, inject, signal } from '@angular/core';
import { CommonModule } from '@angular/common';
import { WeatherService } from '../../services/weather';
import { getColorByBrightness } from '../../utils/weather/get-color-by-brightness';
import { CloudsComponent } from './clouds/clouds';
import { RainComponent } from './rain/rain';
import { MoonComponent } from './moon/moon';
import { SunComponent } from './sun/sun';
import { StarsComponent } from './stars/stars';
import { DayService } from '../../services/day';

@Component({
  selector: 'weather',
  imports: [CommonModule, CloudsComponent, RainComponent, MoonComponent, SunComponent, StarsComponent],
  standalone: true,
  templateUrl: './weather.html',
})
export class WeatherComponent {
  protected readonly weatherService = inject(WeatherService);
  protected readonly dayService = inject(DayService);

  protected readonly skyRGB = computed(() => getColorByBrightness([15, 23, 42], [56, 139, 255], this.weatherService.brightness()));
  protected readonly grassRGB = computed(() => getColorByBrightness([50, 60, 42], [100, 160, 62], this.weatherService.brightness(), 0.6));

  protected readonly expanded = signal(true);

  protected toggleExpanded() {
    this.expanded.set(!this.expanded());
  }
}
