import { NoiseFunction2D, createNoise2D } from 'simplex-noise';
import { getSeededRandom } from './functions/seed-random';
import { BIOMES } from '../interfaces/biomes';

export interface TerrainPoint {
  height: number;
  isWater: boolean;
}

interface GeneratorConfig {
  width: number;
  height: number;
  seed: number;
  scale?: number;
  lacunarity?: number;
  persistance?: number;
  octaves?: number;
  lakeProbability?: number;
}

interface Point {
  x: number;
  y: number;
}

export class IslandGenerator {
  private readonly config: Required<GeneratorConfig>;
  private readonly prng: () => number;
  private readonly shapeNoise: NoiseFunction2D;
  private readonly warpNoise: NoiseFunction2D;
  private readonly detailNoise: NoiseFunction2D;

  public constructor(config: GeneratorConfig) {
    this.config = {
      scale: 1.5,
      lacunarity: 2.0,
      persistance: 0.5,
      octaves: 6,
      lakeProbability: 0.3,
      ...config,
    };

    this.prng = getSeededRandom(this.config.seed);

    this.shapeNoise = createNoise2D(this.prng);
    this.warpNoise = createNoise2D(this.prng);
    this.detailNoise = createNoise2D(this.prng);
  }

  public generateMap(): TerrainPoint[][] {
    const { width, height, octaves, persistance, lacunarity, scale, lakeProbability } = this.config;
    const heightMap: number[][] = Array.from({ length: height }, () => new Array<number>(width));

    for (let y = 0; y < height; y++) {
      for (let x = 0; x < width; x++) {
        const nx = (x / width - 0.5) * 2 * (width / height);
        const ny = (y / height - 0.5) * 2;

        const qx = this.warpNoise(nx * 1.5, ny * 1.5);
        const qy = this.warpNoise(nx * 1.5 + 5.2, ny * 1.5 + 1.3);
        const dist = Math.sqrt((nx + qx * 0.3) ** 2 + (ny + qy * 0.3) ** 2);

        let mask = 1.0 - dist;
        mask += this.shapeNoise(nx * 0.8, ny * 0.8) * 0.3;

        const borderFactor = Math.min(x, y, width - 1 - x, height - 1 - y) / (Math.min(width, height) * 0.1);
        mask *= Math.min(1, borderFactor);

        if (mask <= 0) {
          heightMap[y][x] = 0;
          continue;
        }

        let elevation = 0;
        let amplitude = 1;
        let frequency = scale;
        let maxValue = 0;

        for (let index = 0; index < octaves; index++) {
          let noise = this.detailNoise(nx * frequency, ny * frequency);

          if (index > 0) {
            noise = 1 - Math.abs(noise);
            noise *= noise;
          } else {
            noise = (noise + 1) / 2;
          }

          elevation += noise * amplitude;
          maxValue += amplitude;
          amplitude *= persistance;
          frequency *= lacunarity;
        }

        let finalHeight = (elevation / maxValue) * mask;
        finalHeight **= 2.5;
        heightMap[y][x] = Math.max(0, Math.min(1, finalHeight));
      }
    }

    const isWaterMap = this.calculateWaterBodies(heightMap, width, height, lakeProbability);

    return heightMap.map((row, y) =>
      row.map((h, x) => ({
        height: h,
        isWater: isWaterMap[y][x],
      })),
    );
  }

  private calculateWaterBodies(heightMap: number[][], width: number, height: number, lakeProbability: number): boolean[][] {
    const isWater = Array.from({ length: height }, () => new Array<boolean>(width).fill(false));
    const visited = Array.from({ length: height }, () => new Array<boolean>(width).fill(false));

    const lakeThresholds = [
      { min: BIOMES.sea.threshold, max: BIOMES.waterfront.threshold },
      { min: BIOMES.waterfront.threshold, max: BIOMES.grass.threshold },
      { min: BIOMES.grass.threshold, max: BIOMES.forest.threshold },
    ];

    for (let posY = 0; posY < height; posY++) {
      for (let posX = 0; posX < width; posX++) {
        if (visited[posY][posX]) continue;

        const val = heightMap[posY][posX];

        if (val < BIOMES.sea.threshold) {
          isWater[posY][posX] = true;
          visited[posY][posX] = true;
          continue;
        }

        for (const threshold of lakeThresholds) {
          if (val >= threshold.min && val < threshold.max) {
            this.processRegion(posX, posY, width, height, heightMap, visited, isWater, threshold, lakeProbability);
            break;
          }
        }
      }
    }
    return isWater;
  }

  private processRegion(
    startX: number,
    startY: number,
    width: number,
    height: number,
    map: number[][],
    visited: boolean[][],
    isWaterMap: boolean[][],
    threshold: { min: number; max: number },
    lakeProbability: number,
  ) {
    const queue: Point[] = [{ x: startX, y: startY }];
    const region: Point[] = [];
    const regionSet = new Set<number>();

    visited[startY][startX] = true;

    let head = 0;
    while (head < queue.length) {
      const { x, y } = queue[head++];
      region.push({ x, y });
      regionSet.add(y * width + x);

      const dx = [1, -1, 0, 0];
      const dy = [0, 0, 1, -1];

      for (let index = 0; index < 4; index++) {
        const nx = x + dx[index];
        const ny = y + dy[index];

        if (nx >= 0 && nx < width && ny >= 0 && ny < height) {
          const nVal = map[ny][nx];
          if (!visited[ny][nx] && nVal >= threshold.min && nVal < threshold.max) {
            visited[ny][nx] = true;
            queue.push({ x: nx, y: ny });
          }
        }
      }
    }

    let hasLeaks = false;

    for (const { x, y } of region) {
      for (let dy = -2; dy <= 2; dy++) {
        for (let dx = -2; dx <= 2; dx++) {
          const nx = x + dx;
          const ny = y + dy;

          if (nx < 0 || nx >= width || ny < 0 || ny >= height) {
            hasLeaks = true;
            break;
          }

          if (!regionSet.has(ny * width + nx)) {
            if (map[ny][nx] < threshold.max) {
              hasLeaks = true;
              break;
            }
          }
        }
        if (hasLeaks) break;
      }
      if (hasLeaks) break;
    }

    if (!hasLeaks && this.prng() < lakeProbability) {
      for (const point of region) {
        isWaterMap[point.y][point.x] = true;
      }
    }
  }
}
