import { Injectable } from '@angular/core';
import { ChunkElement } from '../utils/generator/chunk-details';
import { BIOMES } from '../utils/interfaces/biomes';
import { PLANTS } from '../utils/interfaces/plants';

@Injectable({ providedIn: 'root' })
export class CacheService {
  public readonly chunkCache = new Map<string, ChunkElement[][] | undefined>();
  public readonly imageCache: Record<string, HTMLImageElement> = {};

  public preloadImages(callback: () => void) {
    const objectsToLoad = [...Object.entries(BIOMES), ...Object.entries(PLANTS)];
    let loadedCount = 0;

    objectsToLoad.forEach(([key, plant]) => {
      const img = new Image();
      img.src = plant.image;
      img.onload = () => {
        this.imageCache[key] = img;
        loadedCount++;
        if (loadedCount === objectsToLoad.length) callback();
      };
      img.onerror = () => {
        console.error(`Błąd ładowania grafiki dla: ${key} pod adresem ${plant.image}`);
        loadedCount++;
        if (loadedCount === objectsToLoad.length) callback();
      };
    });
  }

  public clearChunkCache() {
    this.chunkCache.clear();
  }
}
