import { TerrainPoint } from '../terrain-generator';
import { getMapShade } from './get-map-shade';
import { getPointRGB } from './get-point-color';

export const renderMinimapOnCanvas = (canvas: HTMLCanvasElement, map: TerrainPoint[][], tideLevel?: number): void => {
  const height = map.length;
  const width = map[0]?.length ?? 0;
  if (!width || !height) return;

  canvas.width = width;
  canvas.height = height;

  const ctx = canvas.getContext('2d');
  if (!ctx) return;

  const imageData = ctx.createImageData(width, height);
  const { data } = imageData;

  let index = 0;
  for (let posY = 0; posY < height; posY++) {
    const row = map[posY];
    for (let posX = 0; posX < width; posX++) {
      const [red, green, blue] = getPointRGB(row[posX], tideLevel);

      const shade = getMapShade(map, posX, posY, width, height);

      data[index++] = Math.min(255, red * shade);
      data[index++] = Math.min(255, green * shade);
      data[index++] = Math.min(255, blue * shade);
      data[index++] = 255;
    }
  }

  ctx.putImageData(imageData, 0, 0);
};
