import { Component, ElementRef, effect, inject, output, signal, viewChild } from '@angular/core';
import { renderMinimapOnCanvas } from '../../utils/generator/minimap/render-minimap-on-canvas';
import { renderMinimapMarkerOnCanvas } from '../../utils/generator/minimap/render-minimap-marker-on-canvas';
import { GameService } from '../../services/game/game';
import { PropertiesService } from '../../services/properties';
import { CommonModule } from '@angular/common';

@Component({
  selector: 'minimap',
  imports: [CommonModule],
  standalone: true,
  templateUrl: './minimap.html',
})
export class MinimapComponent {
  private readonly gameService = inject(GameService);
  private readonly propertiesService = inject(PropertiesService);

  public readonly positionChange = output();

  private readonly minimapCanvasRef = viewChild.required<ElementRef<HTMLCanvasElement>>(`minimapCanvas`);

  protected readonly expanded = signal(true);
  private readonly minimapCanvas = signal<HTMLCanvasElement | null>(null);

  public constructor() {
    effect(() => {
      this.setMinimapCanvas();
    });
    effect(() => {
      this.drawMinimapMarker();
    });
  }

  protected onMinimapClick(event: MouseEvent) {
    const target: HTMLCanvasElement = event.target as HTMLCanvasElement;
    const posX = Math.round((event.offsetX / target.clientWidth) * this.propertiesService.sizeX());
    const posY = Math.round((event.offsetY / target.clientHeight) * this.propertiesService.sizeY());
    this.gameService.cameraPos.set({ posX, posY });
    this.positionChange.emit();
  }

  protected toggleExpanded() {
    this.expanded.set(!this.expanded());
  }

  private setMinimapCanvas() {
    const minimapCanvas = document.createElement('canvas');

    renderMinimapOnCanvas(minimapCanvas, this.gameService.terrain());
    this.minimapCanvas.set(minimapCanvas);

    const visibleMinimap = this.minimapCanvasRef().nativeElement;
    visibleMinimap.width = this.propertiesService.sizeX();
    visibleMinimap.height = this.propertiesService.sizeY();
  }

  private drawMinimapMarker() {
    const visibleMinimap = this.minimapCanvasRef().nativeElement;
    const minimapBackingStore = this.minimapCanvas();
    const cam = this.gameService.cameraPos();

    renderMinimapMarkerOnCanvas(visibleMinimap, minimapBackingStore, cam.posX, cam.posY);
  }
}
