import { Component, computed, effect, inject, output, signal } from '@angular/core';
import { FormsModule } from '@angular/forms';
import { CommonModule } from '@angular/common';
import { GameService } from '../../services/game/game';
import { BIOMES } from '../../utils/interfaces/biomes';
import { PropertiesService } from '../../services/properties';

const MAX_HEIGHT = 3000;
const WATER_HEIGHT = BIOMES.sea.threshold * MAX_HEIGHT;

@Component({
  selector: 'info',
  imports: [CommonModule, FormsModule],
  standalone: true,
  templateUrl: './info.html',
})
export class InfoComponent {
  protected readonly propertiesService = inject(PropertiesService);
  protected readonly gameService = inject(GameService);

  public readonly regenerate = output<number>();

  protected readonly newSeed = signal(0);

  protected readonly pointHeight = computed(() => {
    const { posX, posY } = this.gameService.cameraPos();
    const point = this.gameService.terrain()?.[Math.round(posY)]?.[Math.round(posX)];
    const height = point?.height ?? 0;

    return height * (MAX_HEIGHT + WATER_HEIGHT) - WATER_HEIGHT;
  });

  public constructor() {
    effect(() => {
      this.newSeed.set(this.propertiesService.seed());
    });
  }
}
