import { Component, computed, inject } from '@angular/core';
import { WeatherService } from '../../../services/weather';
import { DayService } from '../../../services/day';

@Component({
  selector: 'sun',
  standalone: true,
  templateUrl: './sun.html',
})
export class SunComponent {
  private readonly dayService = inject(DayService);
  private readonly weather = inject(WeatherService);

  protected readonly sunX = computed(() => this.dayService.timeOfDay() * 150 - 25);
  protected readonly sunY = computed(() => -(this.weather.sunElevation() - 1) * 55 + 5);
}
