import { Injectable, computed, signal } from '@angular/core';

const TIME_PER_DAY_MS = 10 * 60 * 990;
const EPOCH_DATE_MS = new Date('2026-01-01T00:00:00Z').getTime();

@Injectable({
  providedIn: 'root',
})
export class DayService {
  private readonly realCurrentTimeMs = signal<number>(Date.now());

  public readonly dayOfYear = computed(() => Math.floor(this.gameDaysElapsed() % 365));
  public readonly gameYear = computed(() => Math.floor(this.gameDaysElapsed() / 365));
  public readonly timeOfDay = computed(() => this.gameDaysElapsed() % 1);
  public readonly formattedTime = computed(() => {
    const totalMinutes = Math.floor(this.timeOfDay() * 24 * 60);
    const hours = Math.floor(totalMinutes / 60)
      .toString()
      .padStart(2, '0');
    const minutes = (totalMinutes % 60).toString().padStart(2, '0');
    return `${hours}:${minutes}`;
  });

  public readonly gameDaysElapsed = computed(() => {
    const elapsedRealMs = this.realCurrentTimeMs() - EPOCH_DATE_MS;
    return Math.max(0, elapsedRealMs / TIME_PER_DAY_MS);
  });

  public tick(currentRealMs: number = Date.now()) {
    this.realCurrentTimeMs.set(currentRealMs);
  }
}
