const MARKER = {
  radius: 5,
  width: 4,
  color: '#ff265c',
};

export function renderMinimapMarkerOnCanvas(
  visibleMinimap: HTMLCanvasElement,
  minimapCanvas: HTMLCanvasElement | null,
  camX: number,
  camY: number,
) {
  const ctx = visibleMinimap.getContext('2d');

  if (!ctx || !minimapCanvas) return;

  ctx.clearRect(0, 0, visibleMinimap.width, visibleMinimap.height);
  ctx.drawImage(minimapCanvas, 0, 0);

  ctx.beginPath();
  ctx.arc(camX, camY, MARKER.radius, 0, Math.PI * 2);

  ctx.lineWidth = MARKER.width;
  ctx.strokeStyle = MARKER.color;
  ctx.stroke();

  ctx.closePath();
}
