import { Component, computed, inject, input } from '@angular/core';
import { CommonModule } from '@angular/common';
import { WeatherService } from '../../../services/weather';
import { DayService } from '../../../services/day';

@Component({
  selector: 'moon',
  imports: [CommonModule],
  standalone: true,
  templateUrl: './moon.html',
})
export class MoonComponent {
  private readonly dayService = inject(DayService);
  private readonly weather = inject(WeatherService);

  public readonly skyRGB = input.required<string>();

  protected readonly moonX = computed(() => {
    const moonTime = (this.dayService.timeOfDay() - this.weather.moonPhase() + 1) % 1;
    return moonTime * 150 - 25;
  });
  protected readonly moonY = computed(() => -(this.weather.moonElevation() - 1) * 55 + 5);

  protected readonly shadowTransform = computed(() => {
    const phase = this.weather.moonPhase();
    let translateXPercentage: number;
    const maxOffset = 105;

    if (phase <= 0.5) {
      const progress = phase * 2;
      translateXPercentage = -progress * maxOffset;
    } else {
      const progressFromEnd = (1 - phase) * 2;
      translateXPercentage = progressFromEnd * maxOffset;
    }

    return `translateX(${translateXPercentage}%)`;
  });
}
