import { ChunkElement } from '../../../utils/generator/chunk-details';
import { getPointRGBString } from '../../../utils/generator/minimap/get-point-color';
import { applyShadingToCtx } from './apply-shading-to-ctx';
import { Shades } from './interfaces';
import { CHUNK_SIZE } from '../../_params';

export const applyChunkColorsToCtx = (
  canvas: HTMLCanvasElement,
  ctx: CanvasRenderingContext2D,
  chunk: ChunkElement[][],
  sX: number,
  sY: number,
  objSize: number,
  drawSize: number,
  shades: Shades,
  step: number,
) => {
  for (let chunkY = 0; chunkY < CHUNK_SIZE; chunkY += step) {
    const microY = Math.floor(sY + chunkY * objSize);
    if (microY + drawSize < 0 || microY > canvas.height + 1) continue;

    const coordV = chunkY / CHUNK_SIZE;

    for (let chunkX = 0; chunkX < CHUNK_SIZE; chunkX += step) {
      const microX = Math.floor(sX + chunkX * objSize);
      if (microX + drawSize < 0 || microX > canvas.width + 1) continue;

      const microElement = chunk[chunkY][chunkX];
      if (!microElement) continue;

      ctx.fillStyle = getPointRGBString({
        height: microElement.height,
        isWater: microElement.isWater,
      });
      ctx.fillRect(microX, microY, drawSize, drawSize);

      applyShadingToCtx(ctx, microX, microY, drawSize, chunkX, coordV, shades);
    }
  }
};
