import { Component, computed, inject } from '@angular/core';
import { CommonModule } from '@angular/common';
import { WeatherService } from '../../../services/weather';
import { getColorByBrightness } from '../../../utils/weather/get-color-by-brightness';

@Component({
  selector: 'clouds',
  imports: [CommonModule],
  standalone: true,
  templateUrl: './clouds.html',
})
export class CloudsComponent {
  private readonly weather = inject(WeatherService);

  protected readonly cloudRGB = computed(() => getColorByBrightness([92, 92, 92], [217, 217, 217], this.weather.brightness(), this.weather.cloudiness()));
}
